async-programming.example:
async Task<string> DownloadAsync() {
    using HttpClient client = new();
    string hasil = await client.GetStringAsync("https://example.com");
    return hasil;
}

var task1 = Task.Run(() => DoWork());
var task2 = Task.Run(() => DoOtherWork());
await Task.WhenAll(task1, task2);

var cts = new CancellationTokenSource();
var task = DownloadAsync(cts.Token);
cts.Cancel(); // batalkan

